example.code:
@dataclass(frozen=True)
class OrderCreated(Event):
    order_id: UUID
    customer_id: UUID
# frozen=True makes any assignment raise FrozenInstanceError at runtime

@dataclass
class OrderUpdated(Event):
    entire_order_data: dict  # Full state snapshot — not a change event

@dataclass(frozen=True)
class OrderItemAdded(Event):
    product_id: UUID
    quantity: int

@dataclass(frozen=True)
class ShippingAddressChanged(Event):
    new_address: dict
# One event per change — intent is explicit, projection subscribes only to what it needs
